	// == Functions.
	/**
	 * Retrieves the casefolded sequence for a given Unicode code point.
	 *
	 * \param cp		The input Unicode code point to fold.
	 * \param outSeq	Pointer to a char32_t array (must hold at least 3 elements) to receive the output.
	 * \return			Returns the number of characters in the sequence, or 0 if it is not in the table.
	 **/
	uint32_t CaseFold::getFoldedSequence(char32_t cp, char32_t* outSeq) {
		// Binary search.
		auto comp = [](const CasefoldTable& entry, char32_t target) {
			return entry.uniChar < target;
		};

		auto it = std::lower_bound(casefoldData, casefoldData + std::size(CaseFold::casefoldData), cp, comp);

		if (it != casefoldData + std::size(CaseFold::casefoldData) && it->uniChar == cp) {
			for (uint32_t i = 0; i < it->newSize; ++i) {
				outSeq[i] = it->loweredResult[i];
			}
			return it->newSize;
		}

		return 0;
	}

